import{_ as e}from"./chunks/文件受限图.DsG20F9s.js";import{_ as i,o as n,c as t,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Image Moderation dan Access Mode","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/Safety/image-moderation-and-access-mode.md","filePath":"ms-MY/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),d={name:"ms-MY/Safety/image-moderation-and-access-mode.md"};function r(s,a,o,m,u,p){return n(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="image-moderation-dan-access-mode" tabindex="-1">Image Moderation dan Access Mode <a class="header-anchor" href="#image-moderation-dan-access-mode" aria-label="Permalink to &quot;Image Moderation dan Access Mode&quot;">​</a></h1><p>Image moderation memberikan age rating kepada uploaded images. Access mode mengawal ratings mana yang boleh dilihat melalui public access.</p><p>Ini mempengaruhi public gallery, public file URLs dan random image API. Ia tidak mengehadkan admin panel. Administrators masih boleh melihat dan manage semua files.</p><h2 id="di-mana-untuk-configure" tabindex="-1">Di Mana Untuk Configure <a class="header-anchor" href="#di-mana-untuk-configure" aria-label="Permalink to &quot;Di Mana Untuk Configure&quot;">​</a></h2><p>Buka admin panel, kemudian pergi ke:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>Settings utama:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="fungsi-access-mode" tabindex="-1">Fungsi Access Mode <a class="header-anchor" href="#fungsi-access-mode" aria-label="Permalink to &quot;Fungsi Access Mode&quot;">​</a></h2><p>Access mode menentukan age ratings mana boleh dipaparkan secara public.</p><p>Current modes:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Publicly Visible Ratings</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>General sahaja</td></tr></tbody></table><p>Default ialah Adult mode.</p><p>Untuk private sites atau sites dengan mature content, Adult mode mungkin sesuai. Untuk public gallery yang lebih conservative, pilih Youth, Teen atau Child mode.</p><h2 id="apa-berlaku-apabila-moderation-diaktifkan" tabindex="-1">Apa Berlaku Apabila Moderation Diaktifkan <a class="header-anchor" href="#apa-berlaku-apabila-moderation-diaktifkan" aria-label="Permalink to &quot;Apa Berlaku Apabila Moderation Diaktifkan&quot;">​</a></h2><p>Apabila moderation diaktifkan, ImgBed memanggil selected moderation provider semasa upload dan menyimpan age rating yang dikesan.</p><p>Ratings utama:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Meaning</th></tr></thead><tbody><tr><td>General</td><td>Safe public content</td></tr><tr><td>R12</td><td>Content sedikit sensitive</td></tr><tr><td>R16</td><td>Content moderately sensitive</td></tr><tr><td>R18</td><td>Adult content</td></tr></tbody></table><p>Moderation result digunakan apabila menentukan public access.</p><p>Jika moderation tidak diaktifkan, atau old files tidak mempunyai rating, files tersebut dianggap unrated. Unrated files tidak dibuang secara automatik daripada public gallery atau random image API hanya kerana tiada rating.</p><h2 id="memilih-moderation-provider" tabindex="-1">Memilih Moderation Provider <a class="header-anchor" href="#memilih-moderation-provider" aria-label="Permalink to &quot;Memilih Moderation Provider&quot;">​</a></h2><p>Available providers termasuk:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>Setiap provider mempunyai requirements berbeza:</p><ul><li>moderatecontent.com biasanya memerlukan API Key.</li><li>nsfwjs biasanya memerlukan API endpoint URL.</li><li>Sightengine memerlukan API user dan API secret.</li></ul><p>Pilih berdasarkan account, availability dan detection quality. Selagi moderation enabled dan dikonfigurasi dengan betul, ImgBed cuba menulis image rating semasa upload.</p><h2 id="kesan-pada-public-gallery" tabindex="-1">Kesan Pada Public Gallery <a class="header-anchor" href="#kesan-pada-public-gallery" aria-label="Permalink to &quot;Kesan Pada Public Gallery&quot;">​</a></h2><p>Public gallery filter files mengikut access mode.</p><p>Examples:</p><ul><li>Adult mode: R18 images boleh muncul.</li><li>Youth mode: R18 images disembunyikan.</li><li>Teen mode: R16 dan R18 images disembunyikan.</li><li>Child mode: hanya General images ditunjukkan.</li></ul><p>Ini hanya mempengaruhi normal public access. Admin panel masih menunjukkan semua files.</p><h2 id="kesan-pada-public-file-urls" tabindex="-1">Kesan Pada Public File URLs <a class="header-anchor" href="#kesan-pada-public-file-urls" aria-label="Permalink to &quot;Kesan Pada Public File URLs&quot;">​</a></h2><p>Public file URLs ialah direct image links yang dibuka oleh visitors.</p><p>Jika file rating dibenarkan oleh current access mode, ImgBed return original image.</p><p>Jika rating melebihi allowed level, normal public access tidak return original image. Sebaliknya, ImgBed return configured blocked result atau blocked fallback image.</p><p>Example:</p><ul><li>Current mode ialah Child mode.</li><li>Satu image mempunyai rating R18.</li><li>Visitor membuka public URL secara langsung.</li><li>ImgBed tidak return R18 original image kepada visitor tersebut.</li></ul><p><img src="'+e+'" alt="Restricted file image" loading="lazy"></p><p>Administrators yang melihat files dalam admin panel tidak terjejas oleh restriction ini.</p><h2 id="kesan-pada-random-image-api" tabindex="-1">Kesan Pada Random Image API <a class="header-anchor" href="#kesan-pada-random-image-api" aria-label="Permalink to &quot;Kesan Pada Random Image API&quot;">​</a></h2><p>Random image API juga filter candidate pool mengikut access mode.</p><p>Dalam Child mode, random images dipilih hanya daripada General-rated files.</p><p>Dalam Youth mode, random images boleh datang daripada General, R12 dan R16 files, tetapi bukan R18 files.</p><p>Ini menghalang random image API daripada bypass public gallery restrictions.</p><h2 id="hubungan-dengan-list-rules" tabindex="-1">Hubungan Dengan List Rules <a class="header-anchor" href="#hubungan-dengan-list-rules" aria-label="Permalink to &quot;Hubungan Dengan List Rules&quot;">​</a></h2><p>Access mode bukan satu-satunya public access rule. Ia berfungsi bersama allow/block list rules.</p><p>Secara ringkas:</p><ul><li>Allowlisted content diutamakan sebagai public.</li><li>Blocklisted content tidak boleh dilihat terus oleh regular visitors.</li><li>Content yang tidak berada dalam mana-mana list akan disemak mengikut access mode.</li></ul><p>Jika image dihadkan oleh age rating dan list rules, regular visitors tetap tidak boleh melihat original file secara langsung.</p><h2 id="recommended-settings" tabindex="-1">Recommended Settings <a class="header-anchor" href="#recommended-settings" aria-label="Permalink to &quot;Recommended Settings&quot;">​</a></h2><p>Untuk public sites:</p><ul><li>Enable moderation.</li><li>Pilih access mode yang sesuai dengan audience site.</li><li>Gunakan Child mode atau Teen mode untuk visitors semua umur.</li><li>Elakkan Adult mode jika tidak mahu mature content dipaparkan secara public.</li><li>Review file ratings dalam admin panel dan adjust manually apabila perlu.</li></ul><p>Untuk private atau personal sites:</p><ul><li>Adult mode biasanya memadai.</li><li>Enable moderation jika berguna.</li><li>Review dan adjust ratings dalam admin panel jika perlu.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="adakah-files-akan-hilang-dari-admin-panel-selepas-menukar-access-mode" tabindex="-1">Adakah Files Akan Hilang Dari Admin Panel Selepas Menukar Access Mode? <a class="header-anchor" href="#adakah-files-akan-hilang-dari-admin-panel-selepas-menukar-access-mode" aria-label="Permalink to &quot;Adakah Files Akan Hilang Dari Admin Panel Selepas Menukar Access Mode?&quot;">​</a></h3><p>Tidak.</p><p>Access mode hanya mempengaruhi normal public access. Ia tidak mempengaruhi admin panel.</p><h3 id="mengapa-public-gallery-menunjukkan-lebih-sedikit-images-selepas-bertukar-ke-child-mode" tabindex="-1">Mengapa Public Gallery Menunjukkan Lebih Sedikit Images Selepas Bertukar Ke Child Mode? <a class="header-anchor" href="#mengapa-public-gallery-menunjukkan-lebih-sedikit-images-selepas-bertukar-ke-child-mode" aria-label="Permalink to &quot;Mengapa Public Gallery Menunjukkan Lebih Sedikit Images Selepas Bertukar Ke Child Mode?&quot;">​</a></h3><p>Child mode hanya membenarkan General-rated files dipaparkan secara public. R12, R16 dan R18 files akan difilter keluar.</p><h3 id="bolehkah-public-urls-masih-membuka-adult-images" tabindex="-1">Bolehkah Public URLs Masih Membuka Adult Images? <a class="header-anchor" href="#bolehkah-public-urls-masih-membuka-adult-images" aria-label="Permalink to &quot;Bolehkah Public URLs Masih Membuka Adult Images?&quot;">​</a></h3><p>Jika current access mode tidak membenarkan rating tersebut, normal public URLs tidak return original image.</p><h3 id="bolehkah-random-image-api-return-restricted-images" tabindex="-1">Bolehkah Random Image API Return Restricted Images? <a class="header-anchor" href="#bolehkah-random-image-api-return-restricted-images" aria-label="Permalink to &quot;Bolehkah Random Image API Return Restricted Images?&quot;">​</a></h3><p>Tidak.</p><p>Random image API filter candidates mengikut current access mode.</p><h3 id="apa-berlaku-kepada-old-unrated-images" tabindex="-1">Apa Berlaku Kepada Old Unrated Images? <a class="header-anchor" href="#apa-berlaku-kepada-old-unrated-images" aria-label="Permalink to &quot;Apa Berlaku Kepada Old Unrated Images?&quot;">​</a></h3><p>Unrated images tidak disembunyikan secara automatik hanya kerana tiada moderation results. Anda boleh adjust ratings kemudian dalam admin panel.</p>',67)])])}const k=i(d,[["render",r]]);export{g as __pageData,k as default};
